176→    pub fn record_sample(&mut self, predicted_path_hash: u64, actual_path_hash: u64) {
177→        if self.is_disabled() {
178→            return;
179→        }
180→        self.samples_taken += 1;
181→        if predicted_path_hash != actual_path_hash {
182→            self.mispredictions += 1;
